def dgd_update(M, key, target, dim, alpha, eta):
    activation = [0.0] * dim
    for i in range(dim):
        s = 0.0
        row = M[i]
        for j in range(dim):
            s += row[j] * key[j]
        activation[i] = s

    error = [activation[i] - target[i] for i in range(dim)]

    for i in range(dim):
        row = M[i]
        ei = error[i]
        ki = key[i]
        for j in range(dim):
            row[j] = alpha * row[j] - eta * (row[j] * ki * key[j] + ei * key[j])
    return M

def dgd_update(M, key, target, dim, alpha, eta):
    activation = [0.0] * dim
    for i in range(dim):
        s = 0.0
        row = M[i]
        for j in range(dim):
            s += row[j] * key[j]
        activation[i] = s

    error = [0.0] * dim
    for i in range(dim):
        error[i] = activation[i] - target[i]

    key_sq_factor = [0.0] * dim
    for i in range(dim):
        key_sq_factor[i] = eta * key[i]

    for i in range(dim):
        row = M[i]
        ei = error[i]
        ki = key[i]
        factor_i = key_sq_factor[i]
        for j in range(dim):
            row[j] = alpha * row[j] - factor_i * key[j] - eta * ei * key[j]

def dgd_update(M, key, target, dim, alpha, eta):
    activation = [0.0] * dim
    for i in range(dim):
        s = 0.0
        row = M[i]
        for j in range(dim):
            s += row[j] * key[j]
        activation[i] = s

    error = [activation[i] - target[i] for i in range(dim)]

    key_norm2 = 0.0
    for v in key:
        key_norm2 += v * v

    if key_norm2 < 1e-12:
        return M

    inv_norm2 = 1.0 / key_norm2
    delta = [error[i] * inv_norm2 for i in range(dim)]

    for i in range(dim):
        row = M[i]
        di = delta[i]
        kj = key[i]
        for j in range(dim):
            if i == j:
                row[j] = row[j] * alpha - eta * di * key[j]
            else:
                row[j] = row[j] - eta * di * key[j]
    return M

