    key_norm2 = sum(k * k for k in key)
    if key_norm2 == 0:
        for i in range(dim):
            for j in range(dim):
                M[i][j] *= alpha
        return M

    inv_norm2 = 1.0 / key_norm2
    delta = [error[i] * inv_norm2 for i in range(dim)]

    for i in range(dim):
        row = M[i]
        di = delta[i]
        ki = key[i]
        for j in range(dim):
            forget = alpha if i == j else 1.0
            row[j] = forget * row[j] - eta * di * key[j]
    return M

